import java.io.*;import java.util.*;class Main{static final class MaxStack{ArrayList<Integer> stack=new ArrayList<>();void push(int x){stack.add(x);}int pop(){return stack.remove(stack.size()-1);}int top(){return stack.get(stack.size()-1);}int peekMax(){int best=stack.get(0);for(int i=1;i<stack.size();i++)best=Math.max(best,stack.get(i));return best;}int popMax(){int maxValue=peekMax();ArrayList<Integer> buf=new ArrayList<>();while(top()!=maxValue)buf.add(pop());pop();for(int i=buf.size()-1;i>=0;i--)push(buf.get(i));return maxValue;}}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder all=new StringBuilder();for(int tc=0;tc<t;tc++){int ops=Integer.parseInt(d[idx++]);MaxStack ms=new MaxStack();List<String> out=new ArrayList<>();for(int i=0;i<ops;i++){String op=d[idx++];if(op.equals("C")){ms=new MaxStack();out.add("null");}else if(op.equals("P")){ms.push(Integer.parseInt(d[idx++]));out.add("null");}else if(op.equals("O"))out.add(String.valueOf(ms.pop()));else if(op.equals("T"))out.add(String.valueOf(ms.top()));else if(op.equals("M"))out.add(String.valueOf(ms.peekMax()));else out.add(String.valueOf(ms.popMax()));}if(tc>0)all.append("\n\n");all.append("[").append(String.join(",",out)).append("]");}System.out.print(all);}}
